  ('real-estate-moex-00678', 'real-estate', 'real-estate-moex-108-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '私有土地所有權之移轉、設定負擔或租賃，如有妨害基本國策者，中央地政機關得報請下列何機 關制止之？', '["立法院", "司法院", "行政院", "監察院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "eb18e2baa04f", "answer_pdf_sha1": "718d3b7e2330", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00679', 'real-estate', 'real-estate-moex-108-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '因登記錯誤遺漏或虛偽致受有損害者，由該地政機關負損害賠償責任，此項損害賠償之請求，如 經該地政機關拒絕，受損害人得採取下列何種處理方式？', '["向行政院申訴", "向立法院告發", "向司法機關起訴", "向監察院告發"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "eb18e2baa04f", "answer_pdf_sha1": "718d3b7e2330", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00680', 'real-estate', 'real-estate-moex-108-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '平均地權條例規定照價收買後之土地，其權屬應為？', '["國有", "直轄市、縣（市）有", "鄉鎮有", "公營事業有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "eb18e2baa04f", "answer_pdf_sha1": "718d3b7e2330", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
